/**
 * Generate Pipedream firewall config.
 *
 * Data source: https://pipedream.com/docs/rest-api/auth
 *
 * Pipedream user API keys authenticate via Bearer auth in the Authorization
 * header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://pipedream.com/docs/rest-api/auth";
const PLACEHOLDER_VALUE = "pd_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Pipedream REST API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pipedream",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const pipedreamFirewall = {",
    '  name: "pipedream",',
    '  description: "Pipedream REST API",',
    "  placeholders: {",
    `    PIPEDREAM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.pipedream.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PIPEDREAM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Pipedream firewall config...");
  const ts = generateTypeScript();
  writeOutput("pipedream", ts, import.meta.dirname);
}
